head.script:
scwin.vCurDate = "";

scwin.onpageload = function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");

    ds_condition.set("crryoutBtnYn", "N");
    ds_condition.set("listIoClsCd", "");

    $c.sbm.execute(sbm_RetrieveWrkPlCd);
};

scwin.onUdcCompleted = function() {
    ica_fromDt.setValue(scwin.vCurDate.substring(0, 6) + "01");
    ica_toDt.setValue(scwin.vCurDate);

    lc_wrkPlCd.setFocus();

    let wrkPlCdIdx = lc_wrkPlCd.getSelectedIndex();
    if (wrkPlCdIdx >= 0) {
        ed_bondZoneCdIn.setValue(ds_wrkPlCd.getCellData(wrkPlCdIdx, "bondZoneCd"));
        ed_bondZoneCd.setValue(ds_wrkPlCd.getCellData(wrkPlCdIdx, "bondZoneCd"));
    }
};

scwin.sbm_RetrieveWrkPlCd_submitdone = function(e) {
    if (ds_wrkPlCd.getRowCount() > 0) {
        let wrkPlCdIdx = lc_wrkPlCd.getSelectedIndex();
        if (wrkPlCdIdx >= 0) {
            ed_bondZoneCdIn.setValue(ds_wrkPlCd.getCellData(wrkPlCdIdx, "bondZoneCd"));
            ed_bondZoneCd.setValue(ds_wrkPlCd.getCellData(wrkPlCdIdx, "bondZoneCd"));
        }
    }
};

scwin.sbm_RetrieveWrkPlCd_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.dataSetDebug = function(dataList, isDebug) {
    if (isDebug == true) {
        let obj = dataList;
        let str = "[[[[" + obj.getID() + "]]]]]\n";
        let colInfoArr = obj.getColumnIDList();
        for (let dsRow = 0; dsRow < obj.getRowCount(); dsRow++) {
            for (let dsCol = 0; dsCol < colInfoArr.length; dsCol++) {
                str += "[" + colInfoArr[dsCol] + "] " + obj.getCellData(dsRow, colInfoArr[dsCol]) + ", ";
            }
            str += "\n\n";
        }
        alert(str);
    }
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_qeryList();
};

scwin.f_qeryList = async function(div) {
    let chk = await $c.gus.cfValidate([lc_inOutClsCd1, lc_wrkPlCd]);
    if (!chk) {
        return false;
    }

    await $c.sbm.execute(sbm_Retrieve);
};

scwin.f_CrryoutSave = async function() {
    if (ds_condition.get("listIoClsCd") == "O") {
        await $c.win.alert("반입조회 후 반출 기능을 이용하십시오");
    } else {
        let curRow = ds_searchResult.getRowPosition();
        if (curRow < 0) {
            return;
        }

        ds_searchResultCrryout.removeAll();
        let newRow = ds_searchResultCrryout.insertRow();
        let colList = ds_searchResult.getColumnIDList();
        for (let c = 0; c < colList.length; c++) {
            let colId = colList[c];
            try {
                ds_searchResultCrryout.setCellData(newRow, colId, ds_searchResult.getCellData(curRow, colId));
            } catch(ex) {
            }
        }

        ds_condition.set("crryoutBtnYn", "Y");
        ds_condition.set("ioClsCd", "O");
        lc_crryinoutClsCd.setValue(lc_inOutClsCd1.getValue());
        await scwin.f_qeryList();
    }
};

scwin.f_Save = async function() {
    let curRow = ds_searchResult.getRowPosition();
    if (curRow < 0) {
        return false;
    }

    if (!(ds_searchResult.getCellData(curRow, "sndClsNm") == "미전송"
        || ds_searchResult.getCellData(curRow, "sndClsNm") == "오류")
        && ds_searchResult.getRowStatus(curRow) == "D") {
        await $c.win.alert("전송구분이 오류, 미전송 일때만 수정가능합니다.");
        return false;
    }

    if (!(ds_searchResult.getRowStatus(curRow) == "C"
        || ds_searchResult.getRowStatus(curRow) == "D"
        || ds_searchResult.getRowStatus(curRow) == "U")) {
        await $c.win.alert("변경된 데이터가 없습니다.");
        return false;
    }

    let chkValid = await $c.gus.cfValidate([gr_Regist]);
    if (!chkValid) {
        return;
    }

    scwin.f_copyDataSetForSaveTransfer();

    if (ds_searchResult.getRowStatus(curRow) == "U"
        && ds_dstSetForSaveTransfer.getCellData(0, "chkFlag") == "") {
        ds_dstSetForSaveTransfer.setCellData(0, "chkFlag", "D");
    }

    if (ds_dstSetForSaveTransfer.getCellData(0, "chkFlag") == "") {
        ds_dstSetForSaveTransfer.setCellData(0, "chkFlag", "U");
    }

    if ((ds_dstSetForSaveTransfer.getCellData(0, "shedEndDt") == "" || ds_dstSetForSaveTransfer.getCellData(0, "shedRsn") == "")
        && ds_dstSetForSaveTransfer.getCellData(0, "crryinoutClsCd") == "I") {
        await $c.win.alert("반입시 장치종료일자와 장치위치는 필수 입력사항입니다.");
        return false;
    }

    if (ds_dstSetForSaveTransfer.getCellData(0, "crryinoutClsCd") == "O") {
        if (ds_dstSetForSaveTransfer.getCellData(0, "ed_crryinDeclarNo2") == "") {
            await $c.win.alert("반출시 반입신고번호는 필수 입력사항입니다.");
            return false;
        }
        if (ds_dstSetForSaveTransfer.getCellData(0, "ed_crryinDeclarNo2") != ""
            && ed_crryinDeclarNo2.getValue().length != 10) {
            await $c.win.alert("반입신고번호는 년도(2)+일련번호(8) 총 10자리 입니다.");
            return false;
        }
        ds_dstSetForSaveTransfer.setCellData(0, "crryinDeclarNo", ed_bondZoneCdIn.getValue() + ed_crryinDeclarNo2.getValue());
    }

    if (ds_dstSetForSaveTransfer.getCellData(0, "chkFlag") == "I" && ds_dstSetForSaveTransfer.getCellData(0, "declarDt") == "") {
        ds_dstSetForSaveTransfer.setCellData(0, "declarDt", scwin.vCurDate);
    }

    ds_dstSetForSaveTransfer.setCellData(0, "wrkPlCd", lc_wrkPlCd.getValue());

    await $c.sbm.execute(sbm_Save);
};

scwin.btn_fieldClear_onclick = function(e) {
    scwin.f_FieldClear();
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(lc_inOutClsCd1, null);
    lc_wrkPlCd.setSelectedIndex(0);
    ica_fromDt.setValue(scwin.vCurDate.substring(0, 6) + "01");
    ica_toDt.setValue(scwin.vCurDate);
    lc_wrkPlCd.setFocus();
};

scwin.f_transfer = async function() {
    let curRow = ds_searchResult.getRowPosition();
    if (curRow < 0) {
        return false;
    }

    if (!(ds_searchResult.getCellData(curRow, "sndClsNm") == "미전송"
        || ds_searchResult.getCellData(curRow, "sndClsNm") == "오류")) {
        await $c.win.alert("미전송, 오류인 건만 전송할 수 있습니다.");
        return false;
    }

    scwin.f_copyDataSetForSaveTransfer();
    ds_dstSetForSaveTransfer.setCellData(0, "chkFlag", "T");
    await $c.sbm.execute(sbm_Save);
};

scwin.f_addRow = async function() {
    if (ds_searchResult.getRowCount() == 0) {
        await $c.win.alert("조회를 먼저 하셔야 합니다.");
        return false;
    }

    let newRowIdx = ds_searchResult.insertRow();

    let wrkPlCdIdx = lc_wrkPlCd.getSelectedIndex();
    if (wrkPlCdIdx >= 0) {
        ed_bondZoneCdIn.setValue(ds_wrkPlCd.getCellData(wrkPlCdIdx, "bondZoneCd"));
        ed_bondZoneCd.setValue(ds_wrkPlCd.getCellData(wrkPlCdIdx, "bondZoneCd"));
    }

    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "chkFlag", "I");

    lc_crryinoutClsCd.setValue(lc_inOutClsCd1.getValue());

    if (wrkPlCdIdx >= 0) {
        ed_declarNoBondZoneCd.setValue(ds_wrkPlCd.getCellData(wrkPlCdIdx, "bondZoneCd"));
    }

    let prevRow = ds_searchResult.getRowPosition() - 1;
    if (prevRow >= 0) {
        lc_bondZoneClsCd.setValue(ds_searchResult.getCellData(prevRow, "bondZoneClsCd"));
    }

    if (lc_inOutClsCd1.getValue() == "I") {
        $c.gus.cfDisableObjects([ed_bondZoneCdIn, ed_crryinDeclarNo2]);
        $c.gus.cfEnableObjects([ed_shedEndDt, txt_shedRsn]);
    } else if (lc_inOutClsCd1.getValue() == "O") {
        $c.gus.cfDisableObjects([ed_shedEndDt, txt_shedRsn]);
        $c.gus.cfEnableObjects([ed_bondZoneCdIn, ed_crryinDeclarNo2]);
    }

    lc_bondZoneClsCd.setDisabled(false);
};

scwin.f_deleteRow = function() {
    let curRow = ds_searchResult.getRowPosition();
    if (curRow >= 0) {
        ds_searchResult.removeRow(curRow);
    }
};

scwin.f_undoRow = function() {
    let curRow = ds_searchResult.getRowPosition();
    if (curRow >= 0) {
        ds_searchResult.undoRow(curRow);
    }
};

scwin.f_copyDataSetForSaveTransfer = function() {
    let curRow = ds_searchResult.getRowPosition();
    if (curRow < 0) {
        return;
    }

    ds_dstSetForSaveTransfer.removeAll();
    let newRow = ds_dstSetForSaveTransfer.insertRow();
    let colList = ds_searchResult.getColumnIDList();
    for (let c = 0; c < colList.length; c++) {
        let colId = colList[c];
        try {
            ds_dstSetForSaveTransfer.setCellData(newRow, colId, ds_searchResult.getCellData(curRow, colId));
        } catch(ex) {
        }
    }
};

scwin.f_errorPopUp = async function(row) {
    let docCd = "";
    let curRow = ds_searchResult.getRowPosition();
    if (ds_searchResult.getCellData(curRow, "crryinoutClsCd") == "I") {
        docCd = "5HA";
    } else if (ds_searchResult.getCellData(curRow, "crryinoutClsCd") == "O") {
        docCd = "5HB";
    }
    let declarNo = ds_searchResult.getCellData(curRow, "declarNo");
    let deg = 0;
    let procClsCd = "D";

    let obj = {
        deg: deg,
        docCd: docCd,
        declarNo: declarNo,
        procClsCd: procClsCd
    };

    await $c.win.openPopup("/ui/ds/sd/odrmgnt/odrprewrk/sd_401_05_04p.xml", {
        width: 860,
        height: 580,
        modal: true,
        data: obj
    });
};

scwin.f_chgCntWt = async function() {
    if (ds_searchResultCrryout.getRowCount() > 0) {
        let curRow = ds_searchResult.getRowPosition();
        if (curRow < 0) {
            return;
        }
        if (ds_searchResult.getCellData(curRow, "crryoutBtnYn") == "1") {
            if (Number(ds_searchResult.getCellData(curRow, "cnt")) > Number(ds_searchResultCrryout.getCellData(0, "cntLimit"))) {
                await $c.win.alert("잔여 수량 보다 많습니다.");
                ds_searchResult.setCellData(curRow, "cnt", ds_searchResultCrryout.getCellData(0, "cntLimit"));
                return;
            } else if (Number(ds_searchResult.getCellData(curRow, "wt")) > Number(ds_searchResultCrryout.getCellData(0, "wtLimit"))) {
                await $c.win.alert("잔여 중량 보다 많습니다.");
                ds_searchResult.setCellData(curRow, "wt", ds_searchResultCrryout.getCellData(0, "wtLimit"));
                return;
            }
        }
    }
};

scwin.sbm_Retrieve_submitdone = async function(e) {
    let rowCnt = ds_searchResult.getRowCount();
    if (rowCnt == 0) {
        await $c.win.alert("조회된 데이타가 없습니다.");
    } else {
        ed_bondZoneCd.setValue(ds_searchResult.getCellData(0, "bondZoneCd"));

        if (lc_inOutClsCd1.getValue() == "I") {
            $c.gus.cfDisableObjects([ed_bondZoneCdIn, ed_crryinDeclarNo2]);
            $c.gus.cfEnableObjects([ed_shedEndDt, txt_shedRsn]);
            btn_crryout.setDisabled(false);
            ds_condition.set("listIoClsCd", "I");
        } else if (lc_inOutClsCd1.getValue() == "O") {
            $c.gus.cfDisableObjects([ed_shedEndDt, txt_shedRsn]);
            $c.gus.cfEnableObjects([ed_bondZoneCdIn, ed_crryinDeclarNo2]);
            btn_crryout.setDisabled(true);
            ds_condition.set("listIoClsCd", "O");
        }

        lc_bondZoneClsCd.setDisabled(true);
    }

    if (ds_condition.get("crryoutBtnYn") == "Y") {
        ds_condition.set("crryoutBtnYn", "N");
        await scwin.f_addRow();
        $c.gus.cfDisableObjects([ed_shedEndDt, txt_shedRsn]);
        $c.gus.cfEnableObjects([ed_bondZoneCdIn, ed_crryinDeclarNo2]);

        let curRow = ds_searchResult.getRowPosition();
        ds_searchResult.setCellData(curRow, "crryinDeclarNo", ds_searchResultCrryout.getCellData(0, "declarNoOthers"));
        ds_searchResult.setCellData(curRow, "cnt", ds_searchResultCrryout.getCellData(0, "cntLimit"));
        ds_searchResult.setCellData(curRow, "packUnitCd", ds_searchResultCrryout.getCellData(0, "packUnitCd"));
        ds_searchResult.setCellData(curRow, "wt", ds_searchResultCrryout.getCellData(0, "wtLimit"));
        ds_searchResult.setCellData(curRow, "mchtNmCmpy", ds_searchResultCrryout.getCellData(0, "mchtNmCmpy"));
        ds_searchResult.setCellData(curRow, "mchtname", ds_searchResultCrryout.getCellData(0, "mchtname"));
        ds_searchResult.setCellData(curRow, "frgtKndCd", ds_searchResultCrryout.getCellData(0, "frgtKndCd"));
        ds_searchResult.setCellData(curRow, "addr1", ds_searchResultCrryout.getCellData(0, "addr1"));
        ds_searchResult.setCellData(curRow, "addr2", ds_searchResultCrryout.getCellData(0, "addr2"));
        ds_searchResult.setCellData(curRow, "addr3", ds_searchResultCrryout.getCellData(0, "addr3"));
        ds_searchResult.setCellData(curRow, "comm1", ds_searchResultCrryout.getCellData(0, "comm1"));
        ds_searchResult.setCellData(curRow, "comm2", ds_searchResultCrryout.getCellData(0, "comm2"));
        ds_searchResult.setCellData(curRow, "comm3", ds_searchResultCrryout.getCellData(0, "comm3"));
        ds_searchResult.setCellData(curRow, "comm4", ds_searchResultCrryout.getCellData(0, "comm4"));
        ds_searchResult.setCellData(curRow, "crryoutBtnYn", "1");
    }
};

scwin.sbm_Retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_Tranfer_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.gr_Regist_oncelldblclick = async function(rowIndex, columnIndex, columnId) {
    if (columnId == "sndClsNm") {
        if (ds_searchResult.getCellData(rowIndex, "sndClsNm") == "오류") {
            await scwin.f_errorPopUp(rowIndex);
        } else {
            await $c.win.alert("전송구분이 오류인 경우에만 상세내역이 팝업됩니다.");
        }
    }
};

scwin.sbm_Save_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    ds_searchResultCrryout.removeAll();
    await $c.sbm.execute(sbm_Retrieve);
};

scwin.sbm_Save_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_Tranfer_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
};

scwin.lc_inOutClsCd1_onchange = function(e) {
    lc_crryinoutClsCd.setValue(lc_inOutClsCd1.getValue());
};

scwin.lc_wrkPlCd_onchange = function(e) {
    let wrkPlCdIdx = lc_wrkPlCd.getSelectedIndex();
    if (wrkPlCdIdx >= 0) {
        ed_bondZoneCdIn.setValue(ds_wrkPlCd.getCellData(wrkPlCdIdx, "bondZoneCd"));
        ed_bondZoneCd.setValue(ds_wrkPlCd.getCellData(wrkPlCdIdx, "bondZoneCd"));
    }
};

scwin.btn_transfer_onclick = function(e) {
    scwin.f_transfer();
};

scwin.btn_save_onclick = function(e) {
    scwin.f_Save();
};

scwin.btn_crryout_onclick = function(e) {
    scwin.f_CrryoutSave();
};

scwin.txt_cnt_onchange = function(e) {
    scwin.f_chgCntWt();
};

scwin.txt_wt_onchange = function(e) {
    scwin.f_chgCntWt();
};
